code = """import json
import re

# Get Literature & Fiction books
lit_fiction_books = var_functions.query_db:34

# Get books with perfect 5.0 ratings
perfect_ratings_data = var_functions.query_db:30

# Create a set of book IDs with perfect ratings (numeric IDs)
perfect_rating_ids = set()
for row in perfect_ratings_data:
    perfect_rating_ids.add(row['book_id_num'])

print("Books with perfect 5.0 rating:", len(perfect_rating_ids))
print("First 10:", sorted(list(perfect_rating_ids))[:10])

# Find matching books
matching_books = []
for book in lit_fiction_books:
    book_id = book['book_id']  # e.g., "bookid_1"
    # Extract numeric part
    match = re.search(r'bookid_(\d+)', book_id)
    if match:
        numeric_id = int(match.group(1))
        if numeric_id in perfect_rating_ids:
            # Get review count
            review_info = next((r for r in perfect_ratings_data if r['book_id_num'] == numeric_id), None)
            book_info = {
                'book_id': book_id,
                'title': book['title'],
                'categories': book['categories'],
                'avg_rating': 5.0,
                'review_count': review_info['review_count'] if review_info else 0
            }
            matching_books.append(book_info)

print("\nMatching Literature & Fiction books with 5.0 rating:", len(matching_books))
print("\nMatching books:")
for book in sorted(matching_books, key=lambda x: x['book_id']):
    print(f"{book['book_id']}: {book['title']} (Reviews: {book['review_count']})")

# Print in required format
result = json.dumps(matching_books, indent=2)
print("__RESULT__:")
print(result)"""

